const buildPrompt=(b,prevHooks,pspHint)=>{
  const ctxStr = b.ctxGrid.map(c=>`${c.label}: ${c.tags.join(", ")}${c.ev?` [데이터: ${c.ev}]`:""}`).join("\n");
  const prevStr = prevHooks.length>0 ? `\n\n이전에 생성된 아이디어 (제외할 것):\n${prevHooks.map(h=>`- ${h}`).join("\n")}` : "";
  const pspGuide = pspHint ? `이번에는 반드시 관점 ${pspHint}에서만 아이디어를 생성하세요.` : "A, B, C 관점을 골고루 섞어주세요.";
  return `너는 알고리즘 퍼포먼스 숏폼 크리에이티브 디렉터야. 삼양식품의 ${b.nm}(${b.cat}) 브랜드를 위한 숏폼 콘텐츠 아이디어를 생성해.

## 브랜드 정보
- 이름: ${b.nm} (${b.cat})
- 전략: ${b.str} — ${b.strL}
- 핵심: ${b.def}
- 제품 태그: ${b.tags.join(", ")}
- 타깃: ${b.prof.gen} | ${b.prof.age} | ${b.prof.persona}

## 소비자 맥락 데이터 (ListeningMind 실제 데이터)
${ctxStr}

## Discovery Path 키워드
${b.dp.join(", ")}

## CEP 인사이트
${b.cep.join("\n")}

## 3가지 관점
A. 소비자 맥락 조합: WHO/WHEN/WHERE/PAIN/NEED/INTEREST 중 2~3개를 조합. 소비자 상황에서 출발.
B. 검색 여정 발견: PathFinder 데이터의 검색 경로 중간에 콘텐츠를 삽입. "소비자가 이 순서로 이동한다" 근거 필요.
C. 크로스 카테고리: 브랜드와 직접 관련 없는 소비자 관심 카테고리에서 의외의 연결. 후킹에 브랜드명 절대 금지. 소비자 관심사로 시작, 브랜드는 콘텐츠 중반 이후 자연 발견.

${pspGuide}
${prevStr}

## 핵심 원칙
- 첫 1초 비브랜디드 (C관점은 후킹에 브랜드명 절대 금지)
- 소비자 언어로 번역 (브랜드 언어 금지)
- 데이터 근거 포함 (위 맥락 데이터에서 인용)
- 각 아이디어마다 YouTube Shorts용 + Instagram Reels용 별도 기획

## 출력 형식
반드시 아래 JSON 배열만 출력. 다른 텍스트 없이 JSON만. 5개 아이디어.
[
  {
    "score": 90,
    "psp": "A",
    "type": "유형명 (예: 스토리텔링형, 참여형, 비교형, 크로스: 카테고리명)",
    "typeC": "#색상코드",
    "ctx": "맥락 조합 설명",
    "data": "📊 또는 🔀 데이터 근거",
    "hook": "후킹 카피 (따옴표 포함)",
    "hookD": "후킹 설명",
    "scenes": ["씬1", "씬2", "씬3", "씬4"],
    "shorts": {
      "title": "쇼츠 제목",
      "hook": "쇼츠 후킹",
      "hookD": "후킹 전략 설명",
      "scenes": ["장면1 상세", "장면2 상세", "장면3 상세", "장면4 상세"],
      "proof": "제품 증거",
      "cta": "행동 유도",
      "tags": ["#태그1", "#태그2", "#태그3", "#태그4", "#태그5"],
      "time": "업로드 최적시간",
      "cluster": "타깃 클러스터"
    },
    "reels": {
      "title": "릴스 제목",
      "hook": "릴스 후킹",
      "hookD": "후킹 전략 설명",
      "scenes": ["장면1 상세", "장면2 상세", "장면3 상세", "장면4 상세"],
      "proof": "제품 증거",
      "cta": "행동 유도",
      "tags": ["#태그1", "#태그2", "#태그3", "#태그4", "#태그5"],
      "time": "업로드 최적시간",
      "cluster": "타깃 클러스터"
    }
  }
]`;
};

const callAI=async(b,prevHooks,pspHint)=>{
  const resp = await fetch("https://api.anthropic.com/v1/messages",{
    method:"POST",headers:{"Content-Type":"application/json"},
    body:JSON.stringify({
      model:"claude-sonnet-4-20250514",
      max_tokens:4000,
      messages:[{role:"user",content:buildPrompt(b,prevHooks,pspHint)}]
    })
  });
  const d = await resp.json();
  const text = d.content?.map(c=>c.text||"").join("")||"";
  const clean = text.replace(/```json|```/g,"").trim();
  return JSON.parse(clean);
};

const S3=({b,onSelect})=>{
  const [ideas,setIdeas]=useState(b.ideas.sort((a,bx)=>bx.score-a.score).slice(0,5));
  const [ld,setLd]=useState(true);
  const [genCount,setGenCount]=useState(0);
  const [filter,setFilter]=useState("all");
  const [sel,setSel]=useState(null);
  const [prevHooks,setPrevHooks]=useState([]);
  const [err,setErr]=useState(null);
  const [genMsg,setGenMsg]=useState("");
  useEffect(()=>{setTimeout(()=>setLd(false),1000)},[]);

  const pspCycle=["","A","B","C"];

  const handleRegen=async()=>{
    setLd(true);setSel(null);setErr(null);
    const nextGen = genCount+1;
    const pspHint = pspCycle[nextGen % pspCycle.length];
    const msgs = ["새로운 관점에서 아이디어 탐색 중","소비자 맥락 데이터 재분석 중","크로스 카테고리 연결점 탐색 중","검색 여정 새 진입점 발견 중"];
    setGenMsg(msgs[nextGen % msgs.length]);
    try {
      const newIdeas = await callAI(b, prevHooks, pspHint);
      setPrevHooks(prev=>[...prev,...newIdeas.map(x=>x.hook)]);
      setIdeas(newIdeas);
      setGenCount(nextGen);
      setFilter("all");
    } catch(e) {
      console.error(e);
      setErr("AI 생성 중 오류가 발생했습니다. 다시 시도해주세요.");
      // Fallback: rotate static ideas
      const pool = b.ideas;
      const off = ((nextGen)*2) % pool.length;
      setIdeas([...pool.slice(off),...pool.slice(0,off)].slice(0,5));
      setGenCount(nextGen);
    }
    setLd(false);
  };

  const filtered = filter==="all" ? ideas : ideas.filter(x=>x.psp===filter);
  const top5 = filtered.slice(0,5);
  const selectedIdea = sel!==null ? top5[sel] : null;

  if(ld) return(
    <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",minHeight:300,gap:14,animation:"fi .4s"}}>
      <div style={{width:48,height:48,border:`3px solid ${b.c}18`,borderTopColor:b.c,borderRadius:"50%",animation:"sp .7s linear infinite"}}/>
      <div style={{fontSize:14,fontWeight:700,color:b.c}}>{genCount===0?"AI 맥락 매칭 분석 중":genMsg||"새로운 관점에서 생성 중"}</div>
      <div style={{fontSize:10,color:"#bbb"}}>{genCount===0?"3가지 관점 × 소비자 맥락 조합 분석":`#${genCount+1} 생성 — 이전 ${prevHooks.length}개 아이디어 제외`}</div>
      {genCount>0&&<div style={{width:200,height:3,background:"#f0f0f0",borderRadius:2,overflow:"hidden",marginTop:4}}><div style={{width:"60%",height:"100%",background:`linear-gradient(90deg,${b.c},${b.c}80)`,borderRadius:2,animation:"pulse 1.5s ease infinite"}}></div></div>}
    </div>
  );

  return(
  <div style={{animation:"fi .4s"}}>
    {/* Header */}
    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:14}}>
      <div style={{display:"flex",alignItems:"center",gap:6}}>
        <div style={{width:8,height:8,borderRadius:4,background:b.c}}/>
        <span style={{fontSize:15,fontWeight:900}}>AI 추천 맥락 조합 TOP 5</span>
        {genCount>0&&<span style={{background:b.c+"08",color:b.c,padding:"2px 8px",borderRadius:4,fontSize:9,fontWeight:600}}>#{genCount+1} 생성</span>}
        {genCount>0&&<span style={{background:"#f0fdf4",color:"#16a34a",padding:"2px 8px",borderRadius:4,fontSize:8,fontWeight:600,border:"1px solid #dcfce7"}}>AI 실시간</span>}
      </div>
      <button onClick={handleRegen} style={{background:genCount===0?"#fff":`linear-gradient(135deg,${b.c},${b.c}BB)`,border:genCount===0?"1px solid #eee":"none",borderRadius:8,padding:"7px 18px",fontSize:10,fontWeight:700,color:genCount===0?"#888":"#fff",cursor:"pointer",display:"flex",alignItems:"center",gap:5,transition:"all .2s",boxShadow:genCount>0?`0 2px 8px ${b.c}20`:"none"}}
        onMouseEnter={e=>{if(genCount===0){e.currentTarget.style.borderColor=b.c;e.currentTarget.style.color=b.c}}}
        onMouseLeave={e=>{if(genCount===0){e.currentTarget.style.borderColor="#eee";e.currentTarget.style.color="#888"}}}>
        ↻ {genCount===0?"AI 재생성":"다른 관점으로 재생성"}
      </button>
    </div>

    {err&&<div style={{background:"#fef2f2",border:"1px solid #fecaca",borderRadius:8,padding:"8px 14px",marginBottom:12,fontSize:10,color:"#dc2626"}}>{err}</div>}

    {/* Perspective filter */}
    <div style={{display:"flex",gap:6,marginBottom:16,flexWrap:"wrap"}}>
      {PERSP.map(p=><button key={p.id} onClick={()=>{setFilter(p.id);setSel(null)}} style={{background:filter===p.id?(p.id==="all"?b.c:p.id==="A"?"#D4520A":p.id==="B"?"#3b82f6":"#a855f7"):"#fff",color:filter===p.id?"#fff":"#888",border:`1px solid ${filter===p.id?"transparent":"#eee"}`,borderRadius:8,padding:"6px 14px",fontSize:10,fontWeight:700,cursor:"pointer",transition:"all .2s"}}>{p.l}</button>)}
    </div>

    {/* TOP 5 Idea cards */}
    <div style={{display:"flex",flexDirection:"column",gap:14}}>
      {top5.map((idea,idx)=>{
        const isSelected = sel===idx;
        return(
        <div key={idea.hook+idx} onClick={()=>setSel(isSelected?null:idx)}
          style={{background:isSelected?`${b.c}03`:"#fff",borderRadius:14,border:`1px solid ${isSelected?b.c+"40":"#f0f0f0"}`,overflow:"hidden",display:"grid",gridTemplateColumns:"160px 1fr",cursor:"pointer",transition:"all .25s",boxShadow:isSelected?`0 4px 20px ${b.c}12`:"none"}}
          onMouseEnter={e=>{if(!isSelected){e.currentTarget.style.borderColor=b.c+"20";e.currentTarget.style.boxShadow=`0 2px 12px ${b.c}08`}}}
          onMouseLeave={e=>{if(!isSelected){e.currentTarget.style.borderColor="#f0f0f0";e.currentTarget.style.boxShadow="none"}}}>
          {/* Phone mockup */}
          <div style={{background:`linear-gradient(180deg,${idea.typeC||b.c}08,#fff)`,padding:"16px",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",borderRight:`1px solid ${isSelected?b.c+"20":"#f0f0f0"}`,position:"relative"}}>
            {isSelected&&<div style={{position:"absolute",top:10,left:10,width:22,height:22,borderRadius:11,background:b.c,display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,color:"#fff"}}>✓</div>}
            <div style={{width:110,height:185,borderRadius:18,background:`linear-gradient(180deg,${idea.typeC||b.c}10,#fff)`,border:`2px solid ${isSelected?b.c+"30":(idea.typeC||b.c)+"18"}`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"14px 10px",position:"relative"}}>
              <div style={{position:"absolute",top:5,width:36,height:3,borderRadius:2,background:(idea.typeC||b.c)+"25"}}/>
              <span style={{background:(idea.typeC||b.c)+"10",color:idea.typeC||b.c,padding:"2px 6px",borderRadius:3,fontSize:7,fontWeight:700,marginBottom:6}}>{idea.psp}. {idea.type}</span>
              <div style={{fontSize:11,fontWeight:800,color:"#333",textAlign:"center",lineHeight:1.4,marginBottom:8}}>"{(idea.hook||"").replace(/"/g,'').slice(0,28)}..."</div>
              <div style={{display:"flex",gap:10,fontSize:8,color:"#bbb"}}><span>♡ {Math.floor((idea.score||85)*3+100)}</span><span>💬 {Math.floor((idea.score||85)*0.5+10)}</span></div>
            </div>
          </div>
          {/* Detail */}
          <div style={{padding:"16px 20px"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:8}}>
              <div style={{display:"flex",alignItems:"center",gap:6}}><span style={{background:b.c,color:"#fff",width:20,height:20,borderRadius:5,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,fontWeight:900}}>{idx+1}</span><span style={{fontSize:13,fontWeight:900}}>{(idea.shorts?.title||idea.hook||"").replace(/"/g,'')}</span></div>
              <div style={{fontSize:24,fontWeight:900,color:(idea.score||85)>=95?b.c:(idea.score||85)>=90?"#f59e0b":"#888"}}>{idea.score||85}</div>
            </div>
            <div style={{display:"flex",gap:3,flexWrap:"wrap",marginBottom:8}}>
              <span style={{background:(idea.typeC||b.c)+"0C",color:idea.typeC||b.c,padding:"2px 8px",borderRadius:4,fontSize:8,fontWeight:700}}>{idea.psp}. {idea.type}</span>
              {(idea.ctx||"").split("|").map((t,i)=><span key={i} style={{background:"#f5f5f5",color:"#666",padding:"2px 8px",borderRadius:4,fontSize:8}}>{t.trim()}</span>)}
            </div>
            <div style={{display:"flex",alignItems:"center",gap:4,marginBottom:8}}><span style={{fontSize:9}}>📊</span><span style={{fontSize:9,color:"#999"}}>{idea.data||""}</span></div>
            <div style={{marginBottom:8}}><div style={{fontSize:8,fontWeight:700,color:b.c,letterSpacing:1,marginBottom:3}}>✦ HOOK</div><div style={{fontSize:14,fontWeight:800,color:"#222"}}>{idea.hook}</div></div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:5}}>
              {(idea.scenes||[]).map((s,i)=><div key={i} style={{background:"#fafafa",borderRadius:6,padding:"6px 8px",border:"1px solid #f0f0f0"}}><div style={{fontSize:7,fontWeight:700,color:"#ccc"}}>씬{i+1}</div><div style={{fontSize:8,color:"#777",lineHeight:1.4}}>{s}</div></div>)}
            </div>
          </div>
        </div>
      )})}
    </div>

    {/* Bottom: Selected idea + Generate button */}
    <div style={{marginTop:20,background:"#fff",borderRadius:14,border:`1px solid ${selectedIdea?b.c+"30":"#f0f0f0"}`,padding:"18px 24px",transition:"all .3s"}}>
      {selectedIdea ? (
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div style={{display:"flex",alignItems:"center",gap:12}}>
            <div style={{width:36,height:36,borderRadius:10,background:b.c+"10",display:"flex",alignItems:"center",justifyContent:"center"}}>
              <span style={{fontSize:16,fontWeight:900,color:b.c}}>{sel+1}</span>
            </div>
            <div>
              <div style={{fontSize:13,fontWeight:800,color:G}}>{(selectedIdea.shorts?.title||selectedIdea.hook||"").replace(/"/g,'')}</div>
              <div style={{display:"flex",gap:4,marginTop:3}}>
                <span style={{background:(selectedIdea.typeC||b.c)+"0C",color:selectedIdea.typeC||b.c,padding:"1px 8px",borderRadius:4,fontSize:8,fontWeight:700}}>{selectedIdea.psp}. {selectedIdea.type}</span>
                <span style={{background:"#f5f5f5",color:"#999",padding:"1px 8px",borderRadius:4,fontSize:8}}>Score {selectedIdea.score||85}</span>
              </div>
            </div>
          </div>
          <button onClick={()=>onSelect(selectedIdea)} style={{background:`linear-gradient(135deg,${b.c},${b.c}BB)`,color:"#fff",border:"none",borderRadius:10,padding:"12px 28px",fontSize:12,fontWeight:800,cursor:"pointer",boxShadow:`0 4px 16px ${b.c}25`,whiteSpace:"nowrap",display:"flex",alignItems:"center",gap:6}}>
            ▸ 숏폼 아이디어 생성
          </button>
        </div>
      ) : (
        <div style={{textAlign:"center",padding:"8px 0"}}>
          <div style={{fontSize:12,color:"#ccc",fontWeight:600}}>위에서 아이디어를 선택하면 숏폼 스토리보드를 생성할 수 있습니다</div>
          <div style={{fontSize:10,color:"#ddd",marginTop:4}}>YouTube Shorts + Instagram Reels 각 1개씩 생성됩니다</div>
        </div>
      )}
    </div>
  </div>);
};

